class Solution:
    def findCommonResponse(self, responses):
        counts = {}
        for day in responses:
            for word in set(day):
                counts[word] = counts.get(word, 0) + 1
        best = None
        best_count = -1
        for word in sorted(counts):
            if counts[word] > best_count:
                best_count = counts[word]
                best = word
        return best

